#!/usr/bin/env python3
"""
Full translation of all boki2 quiz questions to Japanese.
Strategy: Write complete translations for each question/options inline.
"""
import json, os

D = r"C:\Users\haro\.openclaw\workspace\boki2-study\src\data"

def rw(fn, data):
    p = os.path.join(D, fn)
    with open(p,'r',encoding='utf-8') as f: old = json.load(f)
    out = []
    for i, o in enumerate(old):
        n = data[i]
        item = {"category": n[0], "question": n[1], "options": [], "explanation": o["explanation"]}
        for j, opt in enumerate(o["options"]):
            item["options"].append({"text": n[2][j], "correct": opt["correct"]})
        for k in ("steps",):
            if k in o: item[k] = o[k]
        out.append(item)
    with open(p,'w',encoding='utf-8') as f: json.dump(out, f, ensure_ascii=False, indent=2)
    print(f"  {fn}: {len(out)} questions written")

